@font-face {
	font-family: "Game Of Squids";
	font-weight: normal;
    font-style: normal;
	src: url("./fonts/Game-Of-Squids.otf") format("otf"),
	url("./fonts/Game-Of-Squids.eot") format("eot"),
	url("./fonts/Game-Of-Squids.woff2") format("woff2"),
	url("./fonts/Game-Of-Squids.woff")	format("woff");
}

*{
	margin: 0;
	padding: 0;
	text-decoration: none;
	box-sizing: border-box;
	font-family: sans-serif;
}

body{
	background: url(../img/dalgonabg.jpg);
	background-size: cover;
}

.widget__login{
    display: flex;
    flex-direction: column-reverse;
    align-items: center;
}

.widget__content{
	margin-top: 40px;
}

.box-form{
	display: flex;
	flex-direction: column;
	align-items: center;
	width: 35vw;
    padding: 3rem 1.5rem;
	background: rgb(0, 0, 0, 0.9);
	box-shadow: 0px 0px 22px #000;
	text-align: center;
}

.box .solution-text{
	font-family: "Game Of Squids";
	color: #ff00b2;
	padding: 0 50px;
	font-size: 1rem;
	width: 100%;
}

.box h1{
	color: #ff00b2;
}

.box span{
	color: #ff7ad7;
}

.box img{
	width: 150px;
	padding: 1rem;
}

.box img.text-img{
	width: 200px;
}

.box input[type="text"],.box input[type="password"]{
	display: block;
	margin: 1.5rem auto;
	padding: 1rem;
	width: 250px;
	background: none;
	outline: none;
	border: 2px solid #ff00b2;
	text-align: center;
	border-radius: 5px;
	transition: 0.25s;
	color: #fff;
}

.box input[type="text"]:focus,.box input[type="password"]:focus{
	width: 280px;
	border-color: #ff7ad7;
}

.box input[type="submit"]{
	display: block;
	margin: 1.5rem auto;
	padding: .6rem .9rem;
	background: none;
	outline: none;
	border: 2px solid #ff00b2;
	text-align: center;
	border-radius: 5px;
	color: #fff;
}

.box input[type="submit"]:hover{
	color: #000;
	font-weight: 600;
	background: #ff7ad7;
	border-color: #ff7ad7;
}

.box p{
	display: block;
	padding: 1rem;
	background: none;
	text-align: center;
	transition: 0.25s;
	overflow-wrap: break-word;
	color: #fff;
}

.box p:focus{
	width: 280px;
	border-color: #ff7ad7;
}
